#include <stdio.h>
#include <stdlib.h>

long long gcd_ll(long long a, long long b) {
    while (b) {
        long long t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long B, C;
        scanf("%lld %lld", &B, &C);
        long long g = gcd_ll(B, C);
        printf("%lld\n", C / g);
    }
    return 0;
}

